import React from 'react';
import { Link } from 'react-router-dom';

export default function Header() {
  return (
    <header style={{ background: '#00bfa6', padding: '10px', color: '#fff' }}>
      <h1>🎓 CampusConnect</h1>
      <nav>
        <Link to="/dashboard" style={{ margin: '0 10px', color: '#fff' }}>Dashboard</Link>
        <Link to="/profile" style={{ margin: '0 10px', color: '#fff' }}>Profile</Link>
        <Link to="/notes" style={{ margin: '0 10px', color: '#fff' }}>Notes</Link>
        <Link to="/events" style={{ margin: '0 10px', color: '#fff' }}>Events</Link>
      </nav>
    </header>
  );
}
